import { Link, useLocation, useSearch } from "wouter";
import { Menu, X, Info, Mail, Shield, FileText, ChevronRight, Search, BadgeCheck, Sun, Moon, BookOpen } from "lucide-react";
import { useState, useEffect, useRef, useCallback } from "react";
import { useTheme } from "@/hooks/use-theme";
import CurrencySelector from "@/components/CurrencySelector";

const NAV_LINKS = [
  { href: "/?cat=Financial", label: "Financial" },
  { href: "/?cat=Health", label: "Health" },
  { href: "/?cat=Math", label: "Math" },
  { href: "/?cat=Science", label: "Science" },
  { href: "/?cat=Income", label: "Income" },
  { href: "/blog", label: "Blog" },
];

const DRAWER_LINKS = [
  { href: "/blog", label: "Blog", Icon: BookOpen },
  { href: "/about", label: "About Us", Icon: Info },
  { href: "/contact", label: "Contact Us", Icon: Mail },
  { href: "/our-standards", label: "Our Standards", Icon: BadgeCheck },
  { href: "/privacy-policy", label: "Privacy Policy", Icon: Shield },
  { href: "/terms", label: "Terms & Conditions", Icon: FileText },
];

const CLOSE_DELAY = 320;

export default function Navbar() {
  const [location] = useLocation();
  const searchString = useSearch();
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [drawerMounted, setDrawerMounted] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const drawerRef = useRef<HTMLElement>(null);
  const closeTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
  const { toggleTheme, isDark, mounted } = useTheme();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  useEffect(() => {
    document.body.style.overflow = drawerOpen ? "hidden" : "";
    return () => { document.body.style.overflow = ""; };
  }, [drawerOpen]);

  const closeDrawer = useCallback(() => {
    setDrawerOpen(false);
    clearTimeout(closeTimerRef.current);
    closeTimerRef.current = setTimeout(() => setDrawerMounted(false), CLOSE_DELAY);
  }, []);

  const openDrawer = useCallback(() => {
    clearTimeout(closeTimerRef.current);
    setDrawerMounted(true);
    requestAnimationFrame(() =>
      requestAnimationFrame(() => setDrawerOpen(true))
    );
  }, []);

  useEffect(() => () => clearTimeout(closeTimerRef.current), []);

  useEffect(() => {
    closeDrawer();
  }, [location, searchString, closeDrawer]);

  useEffect(() => {
    if (!drawerOpen) return;
    const el = drawerRef.current;
    if (!el) return;
    const focusable = Array.from(
      el.querySelectorAll<HTMLElement>(
        'a[href], button:not([disabled]), [tabindex]:not([tabindex="-1"])',
      ),
    );
    const first = focusable[0];
    const last = focusable[focusable.length - 1];
    setTimeout(() => first?.focus(), 50);
    const trap = (e: KeyboardEvent) => {
      if (e.key === "Escape") { closeDrawer(); return; }
      if (e.key !== "Tab" || focusable.length === 0) return;
      if (e.shiftKey) {
        if (document.activeElement === first) { e.preventDefault(); last?.focus(); }
      } else {
        if (document.activeElement === last) { e.preventDefault(); first?.focus(); }
      }
    };
    document.addEventListener("keydown", trap);
    return () => document.removeEventListener("keydown", trap);
  }, [drawerOpen, closeDrawer]);

  const focusSearch = () => {
    const el = document.querySelector<HTMLInputElement>('input[type="search"]');
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "center" });
      setTimeout(() => el.focus(), 350);
    } else {
      window.location.href = "/search";
    }
  };

  return (
    <>
      <header
        className={`sticky top-0 z-50 bg-white/95 dark:bg-card/95 backdrop-blur-md border-b transition-[border-color,box-shadow] duration-300 ${
          scrolled
            ? "border-border shadow-[0_1px_12px_0_rgba(0,0,0,0.07)] dark:shadow-[0_1px_12px_0_rgba(0,0,0,0.25)]"
            : "border-border/60 shadow-none"
        }`}
      >
        <div className="max-w-6xl mx-auto px-3 sm:px-6 h-[56px] sm:h-[64px] flex items-center justify-between">
          <Link href="/" data-testid="link-logo" className="flex items-center gap-2.5 group">
            <img
              src="/logo-48.png"
              alt="CalcHive logo"
              width={40}
              height={40}
              loading="lazy"
              className="w-8 h-8 sm:w-9 sm:h-9 object-contain select-none flex-shrink-0 transition-transform duration-200 group-hover:scale-110 group-hover:-rotate-[4deg]"
              draggable={false}
            />
            <span className="text-[17px] sm:text-xl font-bold text-foreground tracking-tight">
              Calc<span className="text-primary">Hive</span>
            </span>
          </Link>

          <nav className="hidden md:flex items-center gap-0.5" aria-label="Main navigation">
            {NAV_LINKS.map(({ href, label }) => {
              const catParam = new URLSearchParams(window.location.search).get("cat");
              const isActive = href === "/blog" ? location.startsWith("/blog") : (location === "/" ? catParam === label : false);
              return (
                <Link
                  key={href}
                  href={href}
                  data-testid={`link-nav-${label.toLowerCase()}`}
                  className={`relative block px-3.5 py-2 text-sm font-medium rounded-md transition-colors duration-200 group ${
                    isActive ? "text-foreground" : "text-muted-foreground hover:text-foreground"
                  }`}
                >
                  {label}
                  <span
                    className={`absolute bottom-1 left-3 right-3 h-0.5 rounded-full bg-primary origin-center transition-[opacity,transform] duration-200 ${
                      isActive ? "opacity-100 scale-x-100" : "opacity-0 scale-x-50 group-hover:opacity-60 group-hover:scale-x-100"
                    }`}
                  />
                </Link>
              );
            })}
          </nav>

          <div className="flex items-center gap-1.5">
            <CurrencySelector />
            {/* Search - desktop only */}
            <button
              onClick={focusSearch}
              title="Search calculators"
              className="hidden md:flex items-center justify-center w-9 h-9 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
              aria-label="Search calculators"
            >
              <Search className="w-4 h-4" />
            </button>

            {/* Dark / Light mode toggle */}
            <button
              onClick={toggleTheme}
              title={isDark ? "Switch to light mode" : "Switch to dark mode"}
              aria-label={isDark ? "Switch to light mode" : "Switch to dark mode"}
              className="flex items-center justify-center w-8 h-8 sm:w-9 sm:h-9 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
            >
              {mounted ? (
                isDark
                  ? <Sun className="w-4 h-4 transition-transform duration-300 rotate-0" />
                  : <Moon className="w-4 h-4 transition-transform duration-300 rotate-0" />
              ) : (
                <span className="w-4 h-4" />
              )}
            </button>

            {/* Hamburger menu */}
            <button
              className="flex items-center justify-center w-8 h-8 sm:w-10 sm:h-10 rounded-lg sm:rounded-xl text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
              onClick={openDrawer}
              aria-label="Open menu"
              aria-expanded={drawerOpen}
              data-testid="button-mobile-menu"
            >
              <Menu className="w-5 h-5" />
            </button>

            <Link
              href="/"
              data-testid="link-all-tools"
              className="text-xs sm:text-sm font-semibold text-primary-foreground bg-primary px-3 sm:px-4 py-1.5 rounded-lg hover:opacity-90 active:opacity-80 transition-opacity shadow-sm"
            >
              All Tools
            </Link>
          </div>
        </div>
      </header>

      {drawerMounted && (
        <>
          <div
            className={`fixed inset-0 z-[60] bg-black/40 backdrop-blur-[5px] transition-opacity duration-[250ms] ${
              drawerOpen ? "opacity-100" : "opacity-0 pointer-events-none"
            }`}
            onClick={closeDrawer}
            aria-hidden="true"
          />

          <aside
            ref={drawerRef}
            className={`fixed top-0 left-0 z-[70] h-full w-[78vw] max-w-[320px] bg-card border-r border-border shadow-2xl flex flex-col transition-transform duration-[300ms] ${
              drawerOpen
                ? "translate-x-0 ease-[cubic-bezier(0.32,0.72,0,1)]"
                : "-translate-x-full ease-[cubic-bezier(0.4,0,1,1)]"
            }`}
            aria-label="Site navigation"
            aria-modal="true"
            role="dialog"
          >
            <div className="flex items-center justify-between px-5 h-16 border-b border-border flex-shrink-0">
              <div className="flex items-center gap-2.5">
                <img
                  src="/logo-48.png"
                  alt="CalcHive logo"
                  width={32}
                  height={32}
                  loading="lazy"
                  className="w-8 h-8 object-contain select-none flex-shrink-0"
                  draggable={false}
                />
                <span className="text-lg font-bold text-foreground tracking-tight">
                  Calc<span className="text-primary">Hive</span>
                </span>
              </div>

              <div className="flex items-center gap-1">
                {/* Theme toggle inside drawer header too */}
                <button
                  onClick={toggleTheme}
                  title={isDark ? "Switch to light mode" : "Switch to dark mode"}
                  aria-label={isDark ? "Switch to light mode" : "Switch to dark mode"}
                  className="flex items-center justify-center w-9 h-9 rounded-xl text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
                >
                  {mounted ? (
                    isDark
                      ? <Sun className="w-4 h-4" />
                      : <Moon className="w-4 h-4" />
                  ) : (
                    <span className="w-4 h-4" />
                  )}
                </button>

                <button
                  onClick={closeDrawer}
                  className="flex items-center justify-center w-9 h-9 rounded-xl text-muted-foreground hover:text-foreground hover:bg-muted transition-colors"
                  aria-label="Close menu"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>
            </div>

            <div className="px-5 py-3 border-b border-border flex-shrink-0">
              <CurrencySelector fullWidth />
            </div>

            <nav className="flex-1 overflow-y-auto px-3 py-5 space-y-1">
              <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground px-3 mb-3">Menu</p>
              {DRAWER_LINKS.map(({ href, label, Icon }) => (
                <Link
                  key={href}
                  href={href}
                  className="flex items-center gap-3.5 px-3 py-4 rounded-xl text-foreground hover:bg-accent active:bg-accent/80 transition-colors group"
                >
                  <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0">
                    <Icon className="w-4 h-4 text-primary" />
                  </div>
                  <span className="text-base font-semibold flex-1">{label}</span>
                  <ChevronRight aria-hidden="true" className="w-4 h-4 text-muted-foreground group-hover:text-foreground transition-colors" />
                </Link>
              ))}

              <div className="pt-4 border-t border-border mt-4">
                <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground px-3 mb-3">Tools</p>
                {NAV_LINKS.map(({ href, label }) => (
                  <Link
                    key={href}
                    href={href}
                    className="flex items-center px-3 py-3 rounded-xl text-muted-foreground hover:text-foreground hover:bg-muted active:bg-muted/80 transition-colors text-sm font-medium"
                  >
                    {label}
                  </Link>
                ))}
              </div>
            </nav>

            <div className="flex-shrink-0 border-t border-border px-5 py-4">
              <p className="text-xs text-muted-foreground text-center">
                &copy; 2026 CalcHive - All rights reserved
              </p>
              <p className="text-[10px] text-muted-foreground/60 text-center mt-0.5">
                258 free calculators - No signup required
              </p>
            </div>
          </aside>
        </>
      )}
    </>
  );
}

