import { useLocation } from "wouter";
import { ChevronLeft } from "lucide-react";

export default function BackButton() {
  const [location] = useLocation();

  const isHome = location === "/" || location === "";
  if (isHome) return null;

  function handleBack() {
    if (window.history.length > 1) {
      window.history.back();
    } else {
      window.location.href = "/";
    }
  }

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 pt-3 sm:pt-5 pb-0">
      <button
        onClick={handleBack}
        aria-label="Go back"
        className="inline-flex items-center gap-1.5 text-sm font-medium text-muted-foreground hover:text-foreground transition-colors group w-fit"
      >
        <span className="w-7 h-7 rounded-lg border border-border bg-card flex items-center justify-center group-hover:border-primary/40 group-hover:bg-accent transition-all shadow-xs">
          <ChevronLeft className="w-4 h-4 group-hover:-translate-x-0.5 transition-transform" />
        </span>
        Back
      </button>
    </div>
  );
}
