import { Link, useLocation } from "wouter";
import { ArrowLeft, ArrowRight, ChevronRight, Home } from "lucide-react";
import { calculatorRoutes } from "@/data/siteRoutes";

const WORD_MAP: Record<string, string> = {
  apr: "APR", bac: "BAC", bmi: "BMI", bmr: "BMR", btu: "BTU", cd: "CD", cpm: "CPM",
  ctr: "CTR", dti: "DTI", fha: "FHA", gcf: "GCF", gdp: "GDP", gfr: "GFR", gpa: "GPA",
  heloc: "HELOC", ira: "IRA", irr: "IRR", lcm: "LCM", pmi: "PMI", rmd: "RMD",
  roi: "ROI", tdee: "TDEE", uk: "UK", url: "URL", va: "VA", vat: "VAT",
  youtube: "YouTube", tiktok: "TikTok", instagram: "Instagram", fiverr: "Fiverr",
  upwork: "Upwork", shopify: "Shopify",
};

function titleFromPath(path: string) {
  return path
    .replace(/^\//, "")
    .split("-")
    .map((word) => WORD_MAP[word.toLowerCase()] ?? word.charAt(0).toUpperCase() + word.slice(1))
    .join(" ");
}

function categoryHref(category: string) {
  if (category === "Financial") return "/financial-calculators";
  if (category === "Health") return "/health-calculators";
  if (category === "Math") return "/math-calculators";
  return `/?cat=${encodeURIComponent(category).replace(/%20/g, "+")}`;
}

function getCurrentRoute(path: string) {
  const index = calculatorRoutes.findIndex((route) => route.path === path);
  if (index < 0) return null;
  return {
    route: calculatorRoutes[index],
    previous: calculatorRoutes[(index - 1 + calculatorRoutes.length) % calculatorRoutes.length],
    next: calculatorRoutes[(index + 1) % calculatorRoutes.length],
  };
}

export function CalculatorBreadcrumbs() {
  const [location] = useLocation();
  const current = getCurrentRoute(location.split("?")[0]);
  if (!current) return null;

  const label = titleFromPath(current.route.path);
  return (
    <nav className="max-w-6xl mx-auto px-4 sm:px-6 pt-4" aria-label="Breadcrumb">
      <ol className="flex flex-wrap items-center gap-1.5 text-xs font-semibold text-muted-foreground">
        <li>
          <Link href="/" className="inline-flex items-center gap-1 rounded-md px-1.5 py-1 transition-colors hover:bg-muted hover:text-foreground">
            <Home className="h-3.5 w-3.5" />
            Home
          </Link>
        </li>
        <li aria-hidden="true"><ChevronRight className="h-3.5 w-3.5" /></li>
        <li>
          <Link href={categoryHref(current.route.category)} className="rounded-md px-1.5 py-1 transition-colors hover:bg-muted hover:text-foreground">
            {current.route.category}
          </Link>
        </li>
        <li aria-hidden="true"><ChevronRight className="h-3.5 w-3.5" /></li>
        <li className="rounded-md px-1.5 py-1 text-foreground" aria-current="page">{label}</li>
      </ol>
    </nav>
  );
}

export function CalculatorFooterNavigation() {
  const [location] = useLocation();
  const current = getCurrentRoute(location.split("?")[0]);
  if (!current) return null;

  const previousLabel = titleFromPath(current.previous.path);
  const nextLabel = titleFromPath(current.next.path);

  return (
    <section className="max-w-3xl mx-auto px-4 sm:px-6 pb-12" aria-label="Calculator navigation">
      <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
        <Link
          href={current.previous.path}
          className="group rounded-2xl border border-border bg-card p-4 shadow-sm transition-all hover:border-primary/40 hover:shadow-md"
        >
          <span className="mb-1 flex items-center gap-2 text-xs font-bold uppercase tracking-wide text-muted-foreground">
            <ArrowLeft className="h-3.5 w-3.5 transition-transform group-hover:-translate-x-0.5" />
            Previous
          </span>
          <span className="text-sm font-bold text-foreground">Previous: {previousLabel}</span>
        </Link>
        <Link
          href={current.next.path}
          className="group rounded-2xl border border-border bg-card p-4 text-left shadow-sm transition-all hover:border-primary/40 hover:shadow-md sm:text-right"
        >
          <span className="mb-1 flex items-center gap-2 text-xs font-bold uppercase tracking-wide text-muted-foreground sm:justify-end">
            Next
            <ArrowRight className="h-3.5 w-3.5 transition-transform group-hover:translate-x-0.5" />
          </span>
          <span className="text-sm font-bold text-foreground">Next: {nextLabel}</span>
        </Link>
      </div>
    </section>
  );
}
