import { useState, useEffect, useLayoutEffect, useCallback } from "react";

type Theme = "light" | "dark";

const STORAGE_KEY = "calchive-theme";
let transitionRestoreTimer: number | undefined;

function getInitialTheme(): Theme {
  if (typeof window === "undefined") return "light";
  try {
    const stored = localStorage.getItem(STORAGE_KEY) as Theme | null;
    if (stored === "light" || stored === "dark") return stored;
  } catch { /* ignore */ }
  return window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
}

function temporarilyDisableThemeTransitions(root: HTMLElement) {
  root.classList.add("theme-switching");
  window.clearTimeout(transitionRestoreTimer);

  // Flush before the theme class changes so browser-wide color transitions do
  // not animate hundreds of nodes on slower mobile devices.
  void root.offsetHeight;

  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      root.classList.remove("theme-switching");
    });
  });

  transitionRestoreTimer = window.setTimeout(() => {
    root.classList.remove("theme-switching");
  }, 120);
}

function applyTheme(theme: Theme, skipTransitions = false) {
  const root = document.documentElement;
  if (!skipTransitions) temporarilyDisableThemeTransitions(root);

  if (theme === "dark") {
    root.classList.add("dark");
    root.style.colorScheme = "dark";
  } else {
    root.classList.remove("dark");
    root.style.colorScheme = "light";
  }
}

export function useTheme() {
  const [theme, setThemeState] = useState<Theme>(() => getInitialTheme());
  const [mounted, setMounted] = useState(false);

  // Apply on first mount
  useLayoutEffect(() => {
    const initial = getInitialTheme();
    applyTheme(initial, true);
    setThemeState(initial);
    setMounted(true);
  }, []);

  // Listen for system preference changes (when no stored preference)
  useEffect(() => {
    const mq = window.matchMedia("(prefers-color-scheme: dark)");
    const onChange = (e: MediaQueryListEvent) => {
      try {
        if (!localStorage.getItem(STORAGE_KEY)) {
          const next: Theme = e.matches ? "dark" : "light";
          applyTheme(next);
          setThemeState(next);
        }
      } catch { /* ignore */ }
    };
    mq.addEventListener("change", onChange);
    return () => mq.removeEventListener("change", onChange);
  }, []);

  const setTheme = useCallback((next: Theme) => {
    try { localStorage.setItem(STORAGE_KEY, next); } catch { /* ignore */ }
    applyTheme(next);
    setThemeState(next);
  }, []);

  const toggleTheme = useCallback(() => {
    setTheme(theme === "dark" ? "light" : "dark");
  }, [theme, setTheme]);

  return { theme, setTheme, toggleTheme, mounted, isDark: mounted && theme === "dark" };
}
