import { useEffect } from "react";
import { useLocation } from "wouter";
import { addRecentlyViewed } from "@/hooks/use-recently-viewed";
import { calculatorRoutes } from "@/data/siteRoutes";
import { incrementCalculatorActivity } from "@/lib/calculatorActivity";

const STATIC_PATHS = new Set([
  "/",
  "/about",
  "/contact",
  "/privacy-policy",
  "/terms",
  "/our-standards",
]);

const CALCULATOR_PATHS = new Set(calculatorRoutes.map((route) => route.path));

const pathOnly = (path: string) => path.split("?")[0].split("#")[0].replace(/\/+$/, "") || "/";

const isCalculatorUseButton = (target: EventTarget | null) => {
  if (!(target instanceof Element)) return false;
  const button = target.closest("button");
  if (!button) return false;

  const label = [
    button.textContent,
    button.getAttribute("aria-label"),
    button.getAttribute("title"),
    button.getAttribute("data-testid"),
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();

  return (
    button.type === "submit" ||
    /\b(calculate|convert|solve|generate|roll|encode|decode|estimate|compute)\b/.test(label)
  );
};

export default function RouteTracker() {
  const [location] = useLocation();

  useEffect(() => {
    if (location && !STATIC_PATHS.has(location)) {
      addRecentlyViewed(location);
    }
  }, [location]);

  useEffect(() => {
    const currentPath = pathOnly(location || "");
    if (!CALCULATOR_PATHS.has(currentPath)) return;

    incrementCalculatorActivity(currentPath, "clicks");

    const onCalculatorAction = (event: MouseEvent) => {
      if (isCalculatorUseButton(event.target)) {
        incrementCalculatorActivity(currentPath, "uses");
      }
    };

    document.addEventListener("click", onCalculatorAction, true);
    return () => document.removeEventListener("click", onCalculatorAction, true);
  }, [location]);

  return null;
}
