type PreloadableComponent = ReturnType<typeof lazy> & {
  preload?: () => Promise<unknown>;
};

const routePreloaders = new Map<string, () => Promise<unknown>>();
const preloadedRoutes = new Set<string>();
const chunkReloadKey = "calchive:chunk-reload-attempted";

function isChunkLoadFailure(error: unknown) {
  const message = error instanceof Error ? error.message : String(error);
  return /dynamically imported module|failed to fetch|loading chunk|chunkloaderror|importing a module script/i.test(
    message,
  );
}

async function loadRouteChunk<T>(loader: () => Promise<T>) {
  try {
    const module = await loader();
    if (typeof window !== "undefined") {
      sessionStorage.removeItem(chunkReloadKey);
    }
    return module;
  } catch (error) {
    if (
      typeof window !== "undefined" &&
      isChunkLoadFailure(error) &&
      sessionStorage.getItem(chunkReloadKey) !== "1"
    ) {
      sessionStorage.setItem(chunkReloadKey, "1");
      window.location.reload();
      return new Promise<T>(() => undefined);
    }

    throw error;
  }
}

function lazyWithPreload<T extends { default: ComponentType<unknown> }>(
  loader: () => Promise<T>,
) {
  const guardedLoader = () => loadRouteChunk(loader);
  const Component = lazy(guardedLoader) as PreloadableComponent;
  Component.preload = guardedLoader;
  return Component;
}

function routeComponent(path: string, component: PreloadableComponent) {
  if (component.preload && !routePreloaders.has(path)) {
    routePreloaders.set(path, component.preload);
  }
  return component;
}

function prefetchRoute(path: string) {
  const cleanPath = path.split("?")[0].split("#")[0] || "/";
  const loader = routePreloaders.get(cleanPath);

  if (!loader || preloadedRoutes.has(cleanPath)) return;

  preloadedRoutes.add(cleanPath);
  loader().catch(() => {
    preloadedRoutes.delete(cleanPath);
  });
}

function getInternalPathFromTarget(target: EventTarget | null) {
  if (!(target instanceof Element)) return null;
  const anchor = target.closest<HTMLAnchorElement>("a[href]");
  if (!anchor) return null;

  const url = new URL(anchor.href, window.location.href);
  if (url.origin !== window.location.origin) return null;
  return url.pathname;
}

