function App() {
  const appBase = import.meta.env.BASE_URL;
  const routerBase = appBase === "/" || appBase === "./" ? undefined : appBase.replace(/\/$/, "");
  return (
    <HelmetProvider>
      <CurrencyProvider>
        <WouterRouter base={routerBase}>
          <Router />
          <PWAInstallPrompt />
        </WouterRouter>
      </CurrencyProvider>
    </HelmetProvider>
  );
}

export default App;
