export type Changefreq = "always" | "hourly" | "daily" | "weekly" | "monthly" | "yearly" | "never";

export interface SiteRoute {
  path: string;
  category: string;
  priority: number;
  changefreq: Changefreq;
}

export const SITE_URL = "https://www.calchive.site";

const route = (
  path: string,
  category: string,
  priority = 0.9,
  changefreq: Changefreq = "weekly",
): SiteRoute => ({ path, category, priority, changefreq });

