import { useEffect } from "react";
import { useLocation } from "wouter";

function isEditableTarget(target: EventTarget | null) {
  const element = target as HTMLElement | null;
  if (!element) return false;
  const tag = element.tagName.toLowerCase();
  return element.isContentEditable || tag === "input" || tag === "textarea" || tag === "select";
}

function isVisible(element: HTMLElement) {
  return Boolean(element.offsetParent || element.getClientRects().length);
}

function focusSearch() {
  window.dispatchEvent(new Event("calchive:focus-search"));
  const search = document.querySelector<HTMLInputElement>('input[type="search"][data-testid="input-search"], input[type="search"]');
  if (!search) return false;
  search.scrollIntoView({ behavior: "smooth", block: "center" });
  window.setTimeout(() => search.focus(), 150);
  return true;
}

function triggerCalculateButton() {
  const buttons = Array.from(document.querySelectorAll<HTMLButtonElement>("main button"));
  const button = buttons.find((candidate) => {
    if (!isVisible(candidate) || candidate.disabled) return false;
    if (candidate.closest("nav, header, footer, [data-calculation-history-root], [data-chatbot], [data-newsletter]")) return false;
    return /^calculate\b/i.test(candidate.textContent?.trim() || "");
  });
  button?.click();
}

function isMobileViewport() {
  return window.matchMedia("(max-width: 639px)").matches;
}

export default function KeyboardShortcuts() {
  const [location, navigate] = useLocation();

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const key = event.key.toLowerCase();

      if ((event.ctrlKey || event.metaKey) && key === "k") {
        if (isMobileViewport()) return;
        event.preventDefault();
        if (!focusSearch()) {
          navigate("/?focusSearch=1");
        }
        return;
      }

      if (event.key === "Escape") {
        window.dispatchEvent(new Event("calchive:close-search"));
        return;
      }

      if (event.key === "Enter" && location !== "/" && !event.ctrlKey && !event.metaKey && !event.altKey && !event.shiftKey) {
        const target = event.target as HTMLInputElement | HTMLElement | null;
        if (target instanceof HTMLInputElement && target.type === "search") return;
        if (target instanceof HTMLTextAreaElement || target instanceof HTMLSelectElement) return;
        if (target?.isContentEditable) return;
        if (!isEditableTarget(target) || target instanceof HTMLInputElement) {
          triggerCalculateButton();
        }
      }
    };

    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [location, navigate]);

  return null;
}
