import { CURRENCIES, type CurrencyCode, useCurrency } from "@/lib/currency";
import { ChevronDown } from "lucide-react";

export default function CurrencySelector({ fullWidth = false }: { fullWidth?: boolean }) {
  const { currency, setCurrency } = useCurrency();

  return (
    <label className={`relative flex items-center ${fullWidth ? "w-full" : ""}`}>
      <span className="sr-only">Select currency</span>
      <select
        value={currency.code}
        onChange={(event) => setCurrency(event.target.value as CurrencyCode)}
        className={`appearance-none truncate rounded-lg border border-border/70 bg-muted/45 py-0 pl-2.5 pr-7 text-xs font-semibold text-foreground outline-none transition-colors hover:bg-muted focus:border-primary/50 focus:ring-2 focus:ring-primary/20 dark:bg-muted/30 ${
          fullWidth ? "h-10 w-full" : "h-8 w-[96px] sm:h-9 sm:w-[112px] lg:w-[124px]"
        }`}
        aria-label="Select currency"
      >
        {CURRENCIES.map((item) => (
          <option key={item.code} value={item.code}>
            {item.symbol} {item.name}
          </option>
        ))}
      </select>
      <ChevronDown
        aria-hidden="true"
        className="pointer-events-none absolute right-2 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground"
      />
    </label>
  );
}
