import { createContext, useContext, useEffect, useMemo, useSyncExternalStore, type ReactNode } from "react";

export const CURRENCIES = [
  { code: "USD", symbol: "$", name: "Dollar" },
  { code: "EUR", symbol: "EUR ", name: "Euro" },
  { code: "GBP", symbol: "GBP ", name: "Pound" },
  { code: "AED", symbol: "AED ", name: "UAE Dirham" },
  { code: "SAR", symbol: "SAR ", name: "Saudi Riyal" },
  { code: "CAD", symbol: "C$", name: "Canadian Dollar" },
  { code: "AUD", symbol: "A$", name: "Australian Dollar" },
] as const;

export type CurrencyCode = typeof CURRENCIES[number]["code"];
type Currency = typeof CURRENCIES[number];

const STORAGE_KEY = "calchive-currency";
let currentCurrencyCode: CurrencyCode = "USD";
const listeners = new Set<() => void>();

function isCurrencyCode(value: string | null): value is CurrencyCode {
  return CURRENCIES.some((currency) => currency.code === value);
}

function readStoredCurrency(): CurrencyCode {
  if (typeof window === "undefined") return "USD";
  const stored = window.localStorage.getItem(STORAGE_KEY);
  return isCurrencyCode(stored) ? stored : "USD";
}

function notifyCurrencyChange() {
  listeners.forEach((listener) => listener());
}

export function getCurrency() {
  return CURRENCIES.find((currency) => currency.code === currentCurrencyCode) ?? CURRENCIES[0];
}

export function setCurrencyCode(code: CurrencyCode) {
  currentCurrencyCode = code;
  if (typeof window !== "undefined") {
    window.localStorage.setItem(STORAGE_KEY, code);
  }
  notifyCurrencyChange();
}

export function formatCurrencyValue(
  value: number,
  options: Intl.NumberFormatOptions = {},
) {
  const currency = getCurrency();
  const maximumFractionDigits = options.maximumFractionDigits ?? 2;
  const minimumFractionDigits = options.minimumFractionDigits ?? (maximumFractionDigits === 0 ? 0 : 2);
  const formattedNumber = Number(value).toLocaleString("en-US", {
    ...options,
    style: "decimal",
    minimumFractionDigits,
    maximumFractionDigits,
  });

  return `${currency.symbol}${formattedNumber}`;
}

const CurrencyContext = createContext<{
  currency: Currency;
  setCurrency: (code: CurrencyCode) => void;
}>({
  currency: CURRENCIES[0],
  setCurrency: (_code: CurrencyCode) => {},
});

function subscribe(listener: () => void) {
  listeners.add(listener);
  return () => listeners.delete(listener);
}

function getSnapshot() {
  return currentCurrencyCode;
}

export function useCurrencyVersion() {
  return useSyncExternalStore(subscribe, getSnapshot, getSnapshot);
}

export function CurrencyProvider({ children }: { children: ReactNode }) {
  const currencyCode = useCurrencyVersion();

  useEffect(() => {
    const stored = readStoredCurrency();
    if (stored !== currentCurrencyCode) setCurrencyCode(stored);
  }, []);

  const value = useMemo(() => ({
    currency: getCurrency(),
    setCurrency: setCurrencyCode,
  }), [currencyCode]);

  return <CurrencyContext.Provider value={value}>{children}</CurrencyContext.Provider>;
}

export function useCurrency() {
  return useContext(CurrencyContext);
}



