import { useEffect } from "react";
import { calculatorRoutes } from "@/data/siteRoutes";

const healthPaths = new Set(
  calculatorRoutes.filter((route) => route.category === "Health").map((route) => route.path),
);

type RangeRule = {
  min: number;
  max: number;
  unit?: string;
  allowZero?: boolean;
};

const alertId = "calchive-health-validation-alert";

function formatBound(value: number) {
  return Number.isInteger(value) ? value.toLocaleString() : value.toLocaleString(undefined, { maximumFractionDigits: 2 });
}

function labelFor(input: HTMLInputElement) {
  if (input.id) {
    const label = document.querySelector<HTMLLabelElement>(`label[for="${CSS.escape(input.id)}"]`);
    if (label?.textContent?.trim()) return label.textContent.trim();

    const sliderLabel = document.querySelector<HTMLLabelElement>(`label[for="${CSS.escape(input.id)}-slider"]`);
    if (sliderLabel?.textContent?.trim()) return sliderLabel.textContent.trim();
  }

  const wrapperLabel = input.closest("div")?.querySelector("label")?.textContent?.trim();
  return wrapperLabel || input.getAttribute("aria-label") || input.name || "Input";
}

function ruleFor(label: string, input: HTMLInputElement): RangeRule | null {
  const text = label.toLowerCase();
  const id = input.id.toLowerCase();

  if (text.includes("age")) return { min: 1, max: 120, unit: "years" };
  if (text.includes("current pregnancy week")) return { min: 1, max: 42, unit: "weeks" };
  if (text.includes("cycle length")) return { min: 15, max: 60, unit: "days" };
  if (text.includes("resting heart rate")) return { min: 30, max: 220, unit: "bpm" };
  if (text.includes("serum creatinine")) return { min: 0.1, max: 20, unit: "mg/dL" };

  if (text.includes("height")) {
    if (text.includes("feet")) return { min: 3, max: 8, unit: "ft" };
    if (text.includes("inches") && id.includes("height-in")) return { min: 0, max: 11, unit: "in", allowZero: true };
    if (text.includes("(in") || text.includes(" inch")) return { min: 36, max: 96, unit: "in" };
    return { min: 91.44, max: 243.84, unit: "cm" };
  }

  if (text.includes("weight lifted")) return { min: 1, max: 2_000, unit: "lb" };
  if (text.includes("weight")) {
    if (text.includes("(lb") || text.includes("lbs")) return { min: 66, max: 1_400, unit: "lb" };
    return { min: 30, max: 635, unit: "kg" };
  }

  if (text.includes("waist") || text.includes("neck") || text.includes("hip") || text.includes("wrist")) {
    return { min: 1, max: text.includes("(in") ? 120 : 300, unit: text.includes("(in") ? "in" : "cm" };
  }

  if (text.includes("body fat")) return { min: 1, max: 70, unit: "%" };
  if (text.includes("duration")) return { min: 1, max: 1_440, unit: "minutes" };
  if (text.includes("reps")) return { min: 1, max: 30, unit: "reps" };
  if (text.includes("calories")) return { min: 1, max: 10_000, unit: "calories" };
  if (text.includes("saturated fat") || text.includes("sugar") || text.includes("protein")) return { min: 0, max: 1_000, unit: "g", allowZero: true };
  if (text.includes("number of drinks")) return { min: 0, max: 100, allowZero: true };
  if (text.includes("hours since")) return { min: 0, max: 168, unit: "hours", allowZero: true };
  if (text.includes("current weight gain")) return { min: 0, max: 150, unit: "lb", allowZero: true };

  return null;
}

function validateInput(input: HTMLInputElement) {
  const label = labelFor(input);
  const rule = ruleFor(label, input);
  if (!rule) return null;

  const value = Number(input.value);
  if (!Number.isFinite(value)) return `${label} must be a valid number.`;
  if (!rule.allowZero && value <= 0) return `${label} must be greater than 0.`;
  if (value < rule.min || value > rule.max) {
    const unit = rule.unit ? ` ${rule.unit}` : "";
    return `${label} must be between ${formatBound(rule.min)} and ${formatBound(rule.max)}${unit}.`;
  }
  return null;
}

function readNumber(id: string) {
  const input = document.getElementById(id) as HTMLInputElement | null;
  if (!input) return null;
  const value = Number(input.value);
  return Number.isFinite(value) ? value : null;
}

function validateCrossFields(path: string) {
  if (path === "/bmi-calculator") {
    const ft = readNumber("height-ft");
    const inch = readNumber("height-in");
    if (ft !== null && inch !== null) {
      const total = ft * 12 + inch;
      if (total <= 0) return "Height must be greater than 0.";
      if (total < 36 || total > 96) return "Height must be between 3 feet and 8 feet.";
    }
  }

  if (path === "/body-fat-calculator") {
    const waist = readNumber("waist-bf");
    const neck = readNumber("neck-bf");
    const hip = readNumber("hip-bf");
    const gender = document.querySelector<HTMLButtonElement>("button.bg-primary")?.textContent?.toLowerCase();
    if (waist !== null && neck !== null) {
      const term = gender === "female" && hip !== null ? waist + hip - neck : waist - neck;
      if (term <= 0) return "Circumference measurements must create a positive waist-neck value for the body fat formula.";
    }
  }

  return null;
}

function setResultVisibility(section: HTMLElement | null, visible: boolean) {
  if (!section) return;
  const resultBlocks = section.querySelectorAll<HTMLElement>(".bg-gradient-to-br, .bg-gradient-to-br + .grid, .bg-gradient-to-br + .bg-accent\\/60");
  resultBlocks.forEach((block) => {
    if (visible) {
      if (block.dataset.healthValidationHidden === "true") {
        block.style.removeProperty("display");
        delete block.dataset.healthValidationHidden;
      }
    } else {
      block.dataset.healthValidationHidden = "true";
      block.style.display = "none";
    }
  });
}

function showAlert(section: HTMLElement | null, message: string | null) {
  if (!section) return;
  let alert = section.querySelector<HTMLElement>(`#${alertId}`);

  if (!message) {
    alert?.remove();
    setResultVisibility(section, true);
    return;
  }

  if (!alert) {
    alert = document.createElement("div");
    alert.id = alertId;
    alert.className = "mb-6 rounded-2xl border border-red-300 bg-red-50 px-4 py-3 text-sm text-red-800 dark:border-red-900/70 dark:bg-red-950/30 dark:text-red-200";
    const inputArea = section.querySelector(".mb-8, .mb-6");
    if (inputArea?.parentNode === section) {
      section.insertBefore(alert, inputArea.nextSibling);
    } else {
      section.prepend(alert);
    }
  }

  alert.innerHTML = `<strong class="block font-extrabold">Please check your inputs.</strong><span>${message}</span>`;
  setResultVisibility(section, false);
}

export default function HealthInputValidationGuard({ path }: { path: string }) {
  useEffect(() => {
    if (!healthPaths.has(path)) return;

    let activeSection: HTMLElement | null = null;
    const numberInputs = () => Array.from(document.querySelectorAll<HTMLInputElement>('main input[type="number"]'));

    const prepareMobileInputs = () => {
      for (const input of numberInputs()) {
        if (!input.getAttribute("inputmode")) {
          input.setAttribute("inputmode", input.step && input.step !== "1" ? "decimal" : "numeric");
        }
        input.style.minHeight = "44px";
        input.style.touchAction = "manipulation";
      }
    };

    const validate = () => {
      prepareMobileInputs();
      const section = document.querySelector<HTMLElement>("main section.bg-card");
      activeSection = section;
      let message: string | null = null;
      for (const input of numberInputs()) {
        message = validateInput(input);
        if (message) break;
      }
      message ||= validateCrossFields(path);
      showAlert(section, message);
    };

    const preventInvalidKeys = (event: KeyboardEvent) => {
      const target = event.target;
      if (!(target instanceof HTMLInputElement) || target.type !== "number") return;
      if (["e", "E", "+", "-"].includes(event.key)) event.preventDefault();
    };

    validate();

    const observer = new MutationObserver(validate);
    observer.observe(document.getElementById("main-content") ?? document.body, { childList: true, subtree: true });

    document.addEventListener("input", validate, { capture: true });
    document.addEventListener("change", validate, { capture: true });
    document.addEventListener("keydown", preventInvalidKeys, { capture: true });

    return () => {
      observer.disconnect();
      document.removeEventListener("input", validate, { capture: true });
      document.removeEventListener("change", validate, { capture: true });
      document.removeEventListener("keydown", preventInvalidKeys, { capture: true });
      showAlert(activeSection, null);
    };
  }, [path]);

  return null;
}
