import { useCallback, useEffect, useState } from "react";

type BeforeInstallPromptEvent = Event & {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: "accepted" | "dismissed"; platform: string }>;
};

export default function PWAInstallPrompt() {
  const [installEvent, setInstallEvent] = useState<BeforeInstallPromptEvent | null>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (!("serviceWorker" in navigator)) return;

    window.addEventListener("load", () => {
      navigator.serviceWorker.register("/service-worker.js").catch(() => undefined);
    }, { once: true });
  }, []);

  useEffect(() => {
    const handleBeforeInstallPrompt = (event: Event) => {
      event.preventDefault();
      const promptEvent = event as BeforeInstallPromptEvent;
      setInstallEvent(promptEvent);
      setVisible(true);
    };

    const handleInstalled = () => {
      setVisible(false);
      setInstallEvent(null);
    };

    window.addEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
    window.addEventListener("appinstalled", handleInstalled);

    return () => {
      window.removeEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
      window.removeEventListener("appinstalled", handleInstalled);
    };
  }, []);

  const install = useCallback(async () => {
    if (!installEvent) return;
    await installEvent.prompt();
    await installEvent.userChoice.catch(() => undefined);
    setVisible(false);
    setInstallEvent(null);
  }, [installEvent]);

  const dismiss = useCallback(() => {
    setVisible(false);
  }, []);

  if (!visible || !installEvent) return null;

  return (
    <div className="fixed bottom-4 left-4 z-[70] flex max-w-[calc(100vw-2rem)] items-center gap-2 rounded-2xl border border-border bg-card/95 px-3 py-2 text-sm shadow-xl backdrop-blur supports-[backdrop-filter]:bg-card/80 sm:bottom-5 sm:left-5">
      <button
        type="button"
        onClick={install}
        className="rounded-xl bg-primary px-3 py-2 text-xs font-bold text-primary-foreground shadow-sm transition-transform hover:scale-[1.02] active:scale-95"
      >
        Install CalcHive
      </button>
      <button
        type="button"
        onClick={dismiss}
        className="rounded-xl px-2 py-2 text-xs font-semibold text-muted-foreground transition-colors hover:text-foreground"
        aria-label="Dismiss install prompt"
      >
        Later
      </button>
    </div>
  );
}
